SELECT film.*, area.title as areaName, CONCAT(actor.id, ':', actor.actor) as actorInfo FROM film LEFT JOIN area ON film.area_id = area.id LEFT JOIN actor ON film.actor_id = actor.id
AND film.title LIKE CONCAT('%', #{title}, '%') AND EXISTS (SELECT 1 FROM film_type ft WHERE ft.film_id = film.id AND ft.type_id = #{typeId}) AND film.start LIKE CONCAT('%', #{year}, '%') AND film.area_id = #{areaId} AND film.actor_id = #{actorId}
ORDER BY id DESC

